// Pull the resume text from the incoming JSON
const resume = String($json.resumeText ?? '');

// ── Step 1: Strip characters that break JSON serialization ────────────────
// Null bytes (\x00) — invisible, common in PDF extraction, illegal in JSON
// Control chars except \n (0x0a), \r (0x0d), \t (0x09)
// Lone UTF-16 surrogates (U+D800–U+DFFF) — cause JSON.stringify to throw
const sanitized = resume
  .replace(/\x00/g, '')                          // null bytes
  .replace(/[\x01-\x08\x0b\x0c\x0e-\x1f\x7f]/g, '') // other control chars
  .replace(/[\uD800-\uDFFF]/g, '');              // lone surrogates

// ── Step 2: Whitespace normalization (existing logic) ─────────────────────
const cleaned = sanitized
  .replace(/\r\n/g, '\n')       // Windows newlines → \n
  .replace(/\n{3,}/g, '\n\n')   // collapse 3+ blank lines to 2
  .replace(/[ \t]{2,}/g, ' ')   // collapse extra spaces/tabs
  .replace(/\n\s+/g, '\n')      // remove leading spaces after newlines
  .trim();

// IMPORTANT: "Run Once for Each Item" — return ONE item object (not array)
return {
  json: {
    ...$json,
    resumeText: cleaned,
    clean_resume: cleaned
  },
  binary: $binary   // pass resume file through unchanged
};

