// Input: resume text is in $json.clean_resume
const text = ($json.clean_resume || '').replace(/\r/g, '\n');

// Only look at the top of the resume (where names are)
const top = text.split('\n').slice(0, 12).map(l => l.trim()).filter(Boolean);

// Common junk to ignore
const badLinePatterns = [
  /@/i,                         // email
  /\b(phone|mobile|cell)\b/i,
  /\b(linkedin|github|portfolio|website)\b/i,
  /\b(address|street|ave|st\.|road|rd\.|blvd|suite|ste)\b/i,
  /\b(summary|experience|education|skills)\b/i,
  /\bobjective\b/i,
  /\bwww\./i,
  /\d{3}[-.\s]?\d{3}[-.\s]?\d{4}/, // phone formats
];

// Helper: title-case-ish without being cute
function normalizeName(s) {
  s = s.replace(/\s+/g, ' ').trim();
  // Keep initials/suffixes
  return s;
}

// A "name-like" line: mostly letters/spaces, 2–4 words, not too long
function looksLikeName(line) {
  if (line.length < 4 || line.length > 45) return false;
  if (badLinePatterns.some(rx => rx.test(line))) return false;

  // Remove punctuation that sometimes appears
  const cleaned = line.replace(/[.,|•]/g, ' ').replace(/\s+/g, ' ').trim();

  // Must be mostly letters/spaces/hyphen/apostrophe
  if (!/^[A-Za-zÀ-ÿ'’\- ]+$/.test(cleaned)) return false;

  const parts = cleaned.split(' ').filter(Boolean);

  // Typically 2-4 tokens (First Last, First M Last, First Last Jr)
  if (parts.length < 2 || parts.length > 5) return false;

  // Avoid all-caps section headers that slipped through
  const letters = cleaned.replace(/[^A-Za-z]/g, '');
  const upper = letters.replace(/[^A-Z]/g, '').length;
  const upperRatio = letters.length ? upper / letters.length : 0;

  // All-caps names exist; allow them but require it to be very name-like by token count
  // We'll not reject purely on caps.

  return true;
}

let candidateLine = null;

// First pass: pick the first line that looks like a name
for (const line of top) {
  // Sometimes the first line includes extra separators
  const simplified = line.replace(/[\t|•]+/g, ' ').replace(/\s+/g, ' ').trim();
  if (looksLikeName(simplified)) {
    candidateLine = simplified;
    break;
  }
}

// Fallback: sometimes name and title are on same line: "Jane Doe — Paralegal"
if (!candidateLine) {
  for (const line of top) {
    const simplified = line.replace(/—|–|-/g, '|');
    const parts = simplified.split('|').map(x => x.trim()).filter(Boolean);
    if (parts.length >= 2 && looksLikeName(parts[0])) {
      candidateLine = parts[0];
      break;
    }
  }
}

let first = '';
let last = '';
let confidence = 'Unknown';
let source = 'unknown';

if (candidateLine) {
  source = 'resume_header';
  const cleaned = candidateLine.replace(/[.,]/g, '').replace(/\s+/g, ' ').trim();
  const tokens = cleaned.split(' ').filter(Boolean);

  // Handle suffixes
  const suffixes = new Set(['JR', 'SR', 'II', 'III', 'IV']);
  let t = tokens.map(x => x.replace(/[^A-Za-zÀ-ÿ'’\-]/g, '')).filter(Boolean);

  // If last token is suffix, drop it for name split
  const lastTokUpper = (t[t.length - 1] || '').toUpperCase();
  if (suffixes.has(lastTokUpper)) t = t.slice(0, -1);

  // Simple split: first token = first name, last token = last name
  if (t.length >= 2) {
    first = t[0];
    last = t[t.length - 1];

    // Confidence: high if found in first 3 lines and looks clean
    const lineIndex = top.findIndex(l => l.includes(candidateLine));
    confidence = (lineIndex >= 0 && lineIndex <= 2) ? 'High' : 'Moderate';
  }
}

// Write results onto item
return {
  ...$json,
  candidate_first_name: normalizeName(first),
  candidate_last_name: normalizeName(last),
  candidate_display_name: (last && first) ? `${last}, ${first}` : '',
  name_confidence: confidence,
  name_source: source
};

