const label = labels.find(l => l.name.toLowerCase() === labelName.toLowerCase());
if (!label) throw new Error(`Label not found after create attempt: ${labelName}`);

const criAgentLabel = labels.find(l => l.name.toLowerCase() === 'cri agent');
if (!criAgentLabel) throw new Error('CRI Agent label not found. Please create CRI Agent label in Gmail first.');

