const allItems = $input.all();

let mergeItems = [];
try { mergeItems = $('Merge5').all(); } catch(e) { console.warn('[BCP] Merge5 not available:', e.message); }

let sendItems = [];
try { sendItems = $('SEND - Email Me Results + Attach Resume').all(); } catch(e) { console.warn('[BCP] SEND not available:', e.message); }

const s = (v, len) => {
  if (!v || typeof v !== 'string') return null;
  const t = v.trim();
  return t ? (len ? t.slice(0, len) : t) : null;
};
const ni = (v, max) => {
  if (typeof v !== 'number' || !isFinite(v) || v <= 0) return null;
  const r = Math.round(v);
  return (max && r > max) ? null : r;
};
const nr = (v, min, max) => {
  if (typeof v !== 'number' || !isFinite(v)) return null;
  const r = Math.round(v);
  return (r >= min && r <= max) ? r : null;
};
const em = (v) => {
  const str = s(v, 200);
  return (str && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(str)) ? str : null;
};
const ar = (v, max) => Array.isArray(v)
  ? v.slice(0, max).filter(i => typeof i === 'string' && i.trim())
  : [];
const parseName = (dn) => {
  const clean = s(dn, 200);
  if (!clean) return [null, null];
  const parts = clean.split(/\s+/).filter(Boolean);
  if (parts.length === 0) return [null, null];
  if (parts.length === 1) return [parts[0], null];
  return [parts[0], parts[parts.length - 1]];
};

const result = [];

for (let i = 0; i < allItems.length; i++) {
  const extracted = allItems[i].json.output || {};

  if (i >= mergeItems.length) {
    console.error(`[BCP] mergeItems out of bounds: i=${i}, len=${mergeItems.length}`);
    continue;
  }
  if (sendItems.length > 0 && i >= sendItems.length) {
    console.error(`[BCP] sendItems out of bounds: i=${i}, len=${sendItems.length}`);
    continue;
  }

  const preData  = mergeItems[i].json;
  const sendData = sendItems[i]?.json || {};
  const output   = preData.output || {};

  const displayName = s(preData.subjectCandidateName, 200)
    || s(extracted.candidate_display_name, 200)
    || s(preData.candidate_display_name, 200)
    || 'Unknown';

  let [firstName, lastName] = parseName(displayName);
  if (!firstName) firstName = s(preData.candidate_first_name, 100);
  if (!lastName)  lastName  = s(preData.candidate_last_name, 100);

  let resumeBase64 = null;
  let resumeMimeType = null;
  let resumeFilename = null;

  // Read resumeBinaryBase64 from preData (Merge5) first, then fall back to
  // allItems direct input — the base64 may travel via allItems if Merge5's
  // chain (ANALYZE etc.) drops non-analysis fields.
  const extracted64 = preData.resumeBinaryBase64 || preData.resumeBase64Extracted
    || allItems[i].json.resumeBinaryBase64 || '';

  if (extracted64.length > 512) {
    resumeBase64   = extracted64;
    resumeMimeType = preData.resumeBinaryMimeType || preData.resumeMimeType
      || allItems[i].json.resumeBinaryMimeType || allItems[i].json.resumeMimeType;
    resumeFilename = preData.resumeBinaryFileName || preData.resumeFileName
      || allItems[i].json.resumeBinaryFileName || allItems[i].json.resumeFileName;
  } else {
    console.warn('[BCP] No usable resume base64.',
      '| preData.resumeBinaryBase64 len:', (preData.resumeBinaryBase64 || '').length,
      '| allItems base64 len:', (allItems[i].json.resumeBinaryBase64 || '').length,
      '| preData resume keys:', Object.keys(preData).filter(k => k.startsWith('resume')));
  }

  const payload = {
    candidate_display_name:  displayName,
    candidate_first_name:    firstName,
    candidate_last_name:     lastName,
    applied_role:            s(preData.applied_role, 200),
    resume_email:            em(extracted.resume_email),
    resume_phone:            s(extracted.resume_phone, 50),
    candidate_city:          s(extracted.candidate_city, 100),
    candidate_state:         s(extracted.candidate_state, 50),
    candidate_zip:           s(extracted.candidate_zip, 20),
    current_employer:        s(extracted.current_employer, 200),
    current_title:           s(extracted.current_title, 200),
    years_of_experience:     ni(extracted.years_of_experience, 60),
    work_history_summary:    s(extracted.work_history_summary, 2000),
    education_degree:        s(extracted.education_degree, 100),
    education_major:         s(extracted.education_major, 200),
    education_institution:   s(extracted.education_institution, 200),
    education_year:          nr(extracted.education_year, 1950, 2030),
    certifications:          ar(extracted.certifications, 20),
    bar_admissions:          ar(extracted.bar_admissions, 20),
    languages:               ar(extracted.languages, 20),
    availability_notes:      s(extracted.availability_notes, 500),
    typing_wpm:              ni(extracted.typing_wpm, 300),
    desired_salary:          ni(extracted.desired_salary, 1000000),
    ai_score:                nr(output.composite_score, 0, 100),
    ai_tier:                 s(output.candidate_tier, 100),
    ai_triage_action:        s(output.triage_action, 200),
    ai_analysis:             output || null,
    resume_base64:           resumeBase64,
    resume_mime_type:        resumeMimeType ? s(resumeMimeType, 100) : null,
    resume_filename:         resumeFilename ? s(resumeFilename, 255) : null,
    source:                  'ZipRecruiter',
    intake_email_message_id: s(preData.id, 200),
  };

  result.push({
    json: {
      ...allItems[i].json,
      ...preData,
      threadId:            sendData.threadId || null,
      id:                  sendData.id || null,
      originalMessageId:   preData.emailMsgId || null,
      originalThreadId:    preData.emailThreadId || null,
      applied_role:        preData.applied_role || null,
      crm_payload:         JSON.stringify(payload),
    },
    binary: allItems[i].binary,
  });
}

return result;

